mapper.select:
select blocked_nx_distributer_id
from nx_distributer_block
where blocker_nx_distributer_id = #{blockerNxDistributerId}

mapper.delete:
delete from nx_distributer_block
where blocker_nx_distributer_id = #{blockerNxDistributerId}
  and blocked_nx_distributer_id = #{blockedNxDistributerId}

mapper.select:
select count(*) from nx_distributer_block
where blocker_nx_distributer_id = #{blockerNxDistributerId}
  and blocked_nx_distributer_id = #{blockedNxDistributerId}
